package com.questkeeper.hook;
import org.bukkit.Bukkit; import org.bukkit.plugin.java.JavaPlugin;
public final class IntegrationManager { private final JavaPlugin plugin; public IntegrationManager(JavaPlugin p){plugin=p;} public void load(){if(Bukkit.getPluginManager().getPlugin("Vault")!=null)plugin.getLogger().info("Vault detected; money rewards may be enabled by a provider.");else plugin.getLogger().info("Vault was not found. Money rewards are disabled.");if(Bukkit.getPluginManager().getPlugin("MythicMobs")!=null)plugin.getLogger().info("MythicMobs detected.");else plugin.getLogger().warning("MythicMobs was not found. MythicMob objectives are disabled.");if(Bukkit.getPluginManager().getPlugin("PlaceholderAPI")!=null){plugin.getLogger().info("PlaceholderAPI detected.");if(plugin instanceof com.questkeeper.QuestKeeperPlugin questKeeper) new QuestPlaceholderExpansion(questKeeper).register();}} }
